app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password, action } = req.body;

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({
      error: 'invalid_client',
      error_description: 'Unknown client',
    });
  }

  const actualRedirectUri = redirect_uri || client.redirect_uris[0];

  if (action === 'deny') {
    const url = new URL(actualRedirectUri);
    url.searchParams.set('error', 'access_denied');
    url.searchParams.set('error_description', 'User denied the request');
    if (state) url.searchParams.set('state', state);
    return res.redirect(url.toString());
  }

  const user = await authenticateUser(username, password);
  if (!user) {
    return res.status(401).send('Invalid credentials. <a href="javascript:history.back()">Go back</a>');
  }

  // Generate authorization code
  const code = crypto.randomBytes(32).toString('hex');
  await storeAuthCode(code, {
    client_id: client_id,
    user_id: user.id,
    username: user.username,
    redirect_uri: actualRedirectUri,
    scope: scope || client.scope,
    created_at: Date.now(),
  });

  const url = new URL(actualRedirectUri);
  url.searchParams.set('code', code);
  if (state) url.searchParams.set('state', state);
  res.redirect(url.toString());
});

// Token endpoint
app.post('/token', authenticateClient, async (req, res) => {
  const { grant_type } = req.body;

  switch (grant_type) {
    case 'authorization_code':
      return handleAuthorizationCodeGrant(req, res);
    case 'password':
      return handlePasswordGrant(req, res);
    case 'refresh_token':
      return handleRefreshTokenGrant(req, res);
    case 'client_credentials':
      return handleClientCredentialsGrant(req, res);
    default:
      return res.status(400).json({
        error: 'unsupported_grant_type',
        error_description: `Grant type '${grant_type}' is not supported`,
      });
  }
});

async function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri } = req.body;

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required',
    });
  }

  const authCode = await getAndDeleteAuthCode(code);
  if (!authCode) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code is invalid or expired',
    });
  }

  if (authCode.client_id !== req.client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client',
    });
  }

  if (redirect_uri && authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Redirect URI mismatch',
    });
  }

  const accessToken = generateAccessToken(authCode.user_id, req.client.client_id, authCode.scope);
  const refreshToken = generateRandomToken();

  await storeRefreshToken(refreshToken, {
    user_id: authCode.user_id,
    client_id: req.client.client_id,
    scope: authCode.scope,
    grant_type: 'authorization_code',
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900, // 15 minutes
    refresh_token: refreshToken,
    refresh_token_expires_in: CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    scope: authCode.scope,
  });
}

async function handlePasswordGrant(req, res) {
  const { username, password, scope } = req.body;

  if (!username || !password) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Username and password are required',
    });
  }

  if (!req.client.grant_types.includes('password')) {
    return res.status(400).json({
      error: 'unauthorized_client',
      error_description: 'Client is not authorized for password grant',
    });
  }

  const user = await authenticateUser(username, password);
  if (!user) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid username or password',
    });
  }

  const resolvedScope = scope || req.client.scope;
  const accessToken = generateAccessToken(user.id, req.client.client_id, resolvedScope);
  const refreshToken = generateRandomToken();

  await storeRefreshToken(refreshToken, {
    user_id: user.id,
    client_id: req.client.client_id,
    scope: resolvedScope,
    grant_type: 'password',
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refreshToken,
    refresh_token_expires_in: CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    scope: resolvedScope,
  });
}

async function handleRefreshTokenGrant(req, res) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Refresh token is required',
    });
  }

  const tokenData = await getRefreshToken(refresh_token);
  if (!tokenData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token is invalid or expired',
    });
  }

  if (tokenData.client_id !== req.client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client',
    });
  }

  // If scope is requested, validate it's a subset of the original scope
  let resolvedScope = tokenData.scope;
  if (scope) {
    const originalScopes = new Set(tokenData.scope.split(' '));
    const requestedScopes = scope.split(' ');
    const isSubset = requestedScopes.every((s) => originalScopes.has(s));
    if (!isSubset) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: 'Requested scope exceeds the scope of the refresh token',
      });
    }
    resolvedScope = scope;
  }

  // Issue new access token, REUSE the same refresh token (no rotation)
  const accessToken = generateAccessToken(tokenData.user_id, req.client.client_id, resolvedScope);

  // Update last_used timestamp in Redis without changing the token itself
  const key = REDIS_KEYS.REFRESH_TOKEN + refresh_token;
  const updatedData = { ...tokenData, last_used_at: Date.now() };
  const ttl = await redis.ttl(key);
  if (ttl > 0) {
    await redis.set(key, JSON.stringify(updatedData), 'EX', ttl);
  }

  console.log(`Refresh token reused for user ${tokenData.user_id} (no rotation). TTL remaining: ${ttl}s`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refresh_token, // Same refresh token returned - no rotation
    refresh_token_expires_in: ttl > 0 ? ttl : CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    scope: resolvedScope,
  });
}

async function handleClientCredentialsGrant(req, res) {
  const { scope } = req.body;

  if (!req.client.grant_types.includes('client_credentials')) {
    return res.status(400).json({
      error: 'unauthorized_client',
      error_description: 'Client is not authorized for client credentials grant',
    });
  }

  const resolvedScope = scope || req.client.scope;
  const accessToken = generateAccessToken(req.client.client_id, req.client.client_id, resolvedScope);

  // Client credentials grant typically does not issue refresh tokens
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    scope: resolvedScope,
  });
}

// Token revocation endpoint (RFC 7009)
app.post('/revoke', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Token is required',
    });
  }

  if (token_type_hint === 'refresh_token' || !token_type_hint) {
    const tokenData = await getRefreshToken(token);
    if (tokenData) {
      if (tokenData.client_id !== req.client.client_id) {
        return res.status(400).json({
          error: 'invalid_client',
          error_description: 'Token was not issued to this client',
        });
      }
      await revokeRefreshToken(token);
      console.log(`Refresh token revoked for user ${tokenData.user_id}`);
    }
  }

  // Always return 200 per RFC 7009
  res.status(200).json({ message: 'Token revoked successfully' });
});

