app.get('/token-info/:token', async (req, res) => {
  const tokenData = await getRefreshToken(req.params.token);
  if (!tokenData) {
    return res.status(404).json({ error: 'Token not found or expired' });
  }

  const key = REDIS_KEYS.REFRESH_TOKEN + req.params.token;
  const ttl = await redis.ttl(key);

  res.json({
    ...tokenData,
    ttl_remaining_seconds: ttl,
    ttl_remaining_days: Math.floor(ttl / 86400),
    is_expired: ttl <= 0,
  });
});

